/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /* Use a flat representation of the sub‑matrices to get
     * contiguous memory layout which the compiler can
     * vectorise and the CPU cache can exploit.
     * The original interface must not change. */
    std::vector<double*> Aprime(m), Bprime(m);
    for (int i = 0; i < m; ++i) {
        Aprime[i] = A[i].data();
        Bprime[i] = B[i].data();
    }

    /* Parallelise over the outermost dimension (rows of B).
     * OpenMP schedules the iterations in chunks to minimise
     * load imbalance.  Because each iteration writes to a
     * distinct row of B no race condition occurs. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* brow = Bprime[i];
        double* acol = nullptr;           // will point to column of A
        for (int j = 0; j < n; ++j) {
            double tmp = brow[j];
            /* Sum over k = i+1 .. m-1.  Equivalent to the
             * original nested loop with “A[k][i]” which is the
             * (i,k) entry of the transpose of A. */
            for (int k = i + 1; k < m; ++k) {
                bcol_j: ; // dummy label to keep style
                tmp += Aprime[k][i] * Bprime[k][j];
            }
            brow[j] = alpha * tmp;
        }
    }
}
