/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B)
{
    // Avoid bounds checks by operating on raw pointers
    double *restrict Aarr = A.data();
    double *restrict Barr = B.data();

    // Precompute the coefficient
    const double coeff = 1.0 / 3.0;

    for (int t = 0; t < tsteps; ++t) {
        /* Update B from A */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double left  = Aarr[i-1];
            double mid   = Aarr[i];
            double right = Aarr[i+1];
            Barr[i] = coeff * (left + mid + right);
        }

        /* Update A from B */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double left  = Barr[i-1];
            double mid   = Barr[i];
            double right = Barr[i+1];
            Aarr[i] = coeff * (left + mid + right);
        }
    }
}
