/* Optimize the 3‑point stencil by using contiguous memory access,
   cache‑friendly iteration order and OpenMP parallelisation. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    // conversion to raw pointers for fast indexing
    double **row = new double*[n];
    for (int i = 0; i < n; ++i) row[i] = A[i].data();

    // Since every iteration reads only existing values,
    // we can update A in place safely because the stencil
    // uses only current values from the previous time step
    // (the algorithm as given does this implicitly).
    for (int t = 0; t < tsteps; ++t) {
#pragma omp parallel for schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            double *rmi = row[i-1];
            double *ri  = row[i];
            double *rpi = row[i+1];
            for (int j = 1; j <= n - 2; ++j) {
                // Unroll the inner summation for a 3x3 neighbourhood
                double sum = rmi[j-1] + rmi[j] + rmi[j+1]
                           + ri   [j-1] + ri   [j] + ri   [j+1]
                           + rpi[j-1] + rpi[j] + rpi[j+1];
                ri[j] = sum * (1.0 / 9.0);   // pre‑computed reciprocal
            }
        }
    }

    delete[] row;
}
