```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Flatten the 2‑D matrices into 1‑D arrays for better cache locality.
       The original data are copied only once per call – the cost is
       negligible compared with the inner loops. */
    std::vector<double> a_flat(n * n);
    std::vector<double> b_flat(n * n);

    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            a_flat[i * n + j] = A[i][j];
            b_flat[i * n + j] = B[i][j];
        }

    /* Parallelise the outer loop.  Each iteration writes to a unique
       portion of tmp and y, so no race conditions occur.  A static
       schedule gives good load balance on this dense task. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double tmp_val = 0.0;
        double y_val   = 0.0;
        int i_n = i * n;          // offset for the current row

        /* Inner dot products */
        for (int j = 0; j < n; ++j)
        {
            double xj = x[j];
            tmp_val += a_flat[i_n + j] * xj;
            y_val   += b_flat[i_n + j] * xj;
        }

        tmp[i] = tmp_val;
        y[i]   = alpha * tmp_val + beta * y_val;
    }
}
