```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {
    const double aalpha = alpha;  // local copies for speed
    const double bbeta  = beta;

#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Pointer to the i‑th row of C
        double* Ci = C[i].data();
        // First scale the lower triangular part by beta
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= bbeta;
        }

        // Pointer to the i‑th row of B
        const double* Bi = B[i].data();

        // Perform the rank‑2k update
        for (int k = 0; k < m; ++k) {
            const double aik = A[i][k];
            const double bk  = Bi[k];          // B[i][k]
            const double ak  = A[k][i];        // A[j][k] when j==i? No, instead iterate j below
            const double bk_j = B[i][k];        // same as bk

            for (int j = 0; j <= i; ++j) {
                const double A_jk = A[j][k];
                const double B_jk = B[j][k];
                Ci[j] += aalpha * (A_jk * bk + B_jk * aik);
            }
        }
    }
}
```

This version:
* Uses pointer access for O(1) row indexing.
* Multiplies the scalar `alpha` once per loop.
* Parallelises the outermost loop with OpenMP.
* Keeps the exact mathematical semantics while improving memory locality and reducing overhead.

