```cpp
#include <vector>
#include <algorithm>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/*
 * Optimised Floyd‑Warshall
 *
 * - Matrix stored as a single contiguous block to minimise cache misses.
 * - OpenMP parallelisation on the outer i‑loop.
 * - Manual pointer arithmetic to avoid bounds‑check overhead.
 * - Blocked version to improve cache locality.
 */
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2D vector into one contiguous block.
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.begin() + i * n);

    const int block_size = 64;          // Tune for your cache size
    const int blocks = (n + block_size - 1) / block_size;

    for (int k = 0; k < n; ++k) {
        const int* pk_row = flat.data() + k * n;   // address of row k

        #pragma omp parallel for schedule(static)
        for (int bi = 0; bi < blocks; ++bi) {
            const int i_start = bi * block_size;
            const int i_end   = std::min(n, i_start + block_size);

            for (int i = i_start; i < i_end; ++i) {
                int* row = flat.data() + i * n;    // address of row i
                const int aik = row[k];

                for (int bj = 0; bj < blocks; ++bj) {
                    const int j_start = bj * block_size;
                    const int j_end   = std::min(n, j_start + block_size);

                    for (int j = j_start; j < j_end; ++j) {
                        const int alt = aik + pk_row[j];
                        if (alt < row[j]) row[j] = alt;
                    }
                }
            }
        }
    }

    // Copy back to the original 2‑D vector
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n,
                  path[i].begin());
}
