void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {
    // Form C := alpha*A*A**T + beta*C.
    // A is NxM, C is NxN (lower triangular part is used).

    // Parallelise over the outer dimension.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Pointers to the current row in C and A for fast access.
        double* c_row = C[i].data();

        // Multiply the lower‑triangular part by beta.
        for (int j = 0; j <= i; ++j) {
            c_row[j] *= beta;
        }

        // Accumulate alpha * A[i][k] * A[j][k] over k.
        for (int k = 0; k < m; ++k) {
            double aik = A[i][k];
            for (int j = 0; j <= i; ++j) {
                c_row[j] += alpha * aik * A[j][k];
