/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {

    // Flatten the 2‑D matrix into a 1‑D array for cache friendliness
    std::vector<double> flatA(n * n);
    for (int i = 0; i < n; ++i) {
        const double* src = A[i].data();
        double* dst = &flatA[i * n];
        std::copy(src, src + n, dst);
    }

    // 1st kernel pass: matrix‑vector multiplication (y_1 -> x1)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double* aRow = &flatA[i * n];
        double xi = x1[i];
        for (int j = 0; j < n; ++j) {
            xi += aRow[j] * y_1[j];
        }
        x1[i] = xi;
    }

    // 2nd kernel pass: matrix‑transpose–vector multiplication (y_2 -> x2)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x2[i];
        for (int j = 0; j < n; ++j) {
            xi += flatA[j * n + i] * y_2[j];
        }
        x2[i] = xi;
    }
}
