```cpp
/* Optimised kernel for the Nussinov algorithm.
 * Parallelised over anti‑diagonals using OpenMP.
 * The algorithmic behaviour remains unchanged.
 */
#include <vector>
#include <algorithm>
#include <omp.h>

static inline int match(int b1, int b2) noexcept
{
    return ((b1 + b2) == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Work by increasing distance j-i (anti‑diagonals).  These
    // are independent and therefore safe for parallel execution.
    // For each distance d we iterate all (i, j) with j = i + d.
#pragma omp parallel for schedule(static)
    for (int d = 1; d < n; ++d)                // distance (j-i)
    {
        for (int i = 0; i + d < n; ++i) {      // start index
            int j = i + d;
            int best = table[i][j];           // existing value (zero initially)

            // consider previous positions
            if (j - 1 >= 0)
                best = std::max(best, table[i][j-1]);

            if (i + 1 < n)
                best = std::max(best, table[i+1][j]);

            // possible pairing of i and j
            if (j - 1 >= 0 && i + 1 < n) {
                best = std::max(best,
                                table[i+1][j-1] + match(seq[i], seq[j]));
            }

            // split at any k between i+1 and j-1
            for (int k = i + 1; k < j; ++k)
                best = std::max(best,
                                table[i][k] + table[k+1][j]);

            table[i][j] = best;
        }
    }
}
