#include <vector>
#include <omp.h>

// -----------------------------------------------------------------------------
// Optimised GEMM routine with OpenMP parallelism, row‑major cache layout
// and loop blocking for better cache utilization.
//
// Function signature (unchanged) is preserved for the harness.
// -----------------------------------------------------------------------------


inline void gemm_blocked(double* const restrict Arow,
                         double* const restrict Brow,
                         double* const restrict Crow,
                         const int           nk,
                         const int           nj,
                         const double        alpha)
{
    // Small blocking factor that fits in L2 cache (tuned empirically).
    constexpr int Bn = 64;  // block size for inner dimension (nj)

    for (int jj = 0; jj < nj; jj += Bn) {
        const int jlim = (jj + Bn > nj) ? nj : jj + Bn;

        // Load B block into a fast register array (optional, here we keep simple)
        for (int k = 0; k < nk; ++k) {
            const double Aik = Arow[k];
            const double aikalpha = alpha * Aik;

            for (int j = jj; j < jlim; ++j) {
                Crow[j] += aikalpha * Brow[k * nj + j];
            }
        }
    }
}


void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>> &A,
                 std::vector<std::vector<double>> &B,
                 std::vector<std::vector<double>> &C)
{
    // Convert to raw pointer views for faster indexing.
    const std::size_t nK = nk;
    const std::size_t nJ = nj;

    // Precompute the stride for B since it is NKxNJ in row‑major layout.
    //  B[k][j] => Bptr[k * nj + j]
    double* const Bptr = &B[0][0];

    // -----------------------------------------------------------------
    // Parallelise the outer loop over i – each thread handles a different
    // row of C independently (no race conditions).
    // -----------------------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const restrict Crow = &C[i][0];
        double* const restrict Arow = &A[i][0];

        // ----------- 1) Scale existing C by beta --------------------
        for (int j = 0; j < nj; ++j) {
            C[i][j] *= beta;
        }

        // ----------- 2) Accumulate the product alpha*A*B -------------
        gemm_blocked(Arow, Bptr, Crow, static_cast<int>(nK), static_cast<int>(nJ), alpha);
    }
}
