/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B) {
    const double alpha = 0.2;
    const int width = n;
    // Flatten the 2‑D std::vector for fast pointer arithmetic
    double* restrict aptr = &A[0][0];
    double* restrict bptr = &B[0][0];

    const int stride = width;            // step between rows in memory
    const int last = width - 1;          // last valid index (exclusive)
    const int start = 1;                 // first interior index

#pragma omp parallel
    for (int t = 0; t < tsteps; ++t) {
        // 1st sweep: A → B
#pragma omp for collapse(2) schedule(static)
        for (int i = start; i < last; ++i) {
            const int rowi = i * stride;
            const int rowim1 = (i - 1) * stride;
            const int rowip1 = (i + 1) * stride;
            for (int j = start; j < last; ++j) {
                const int idx = rowi + j;
                bptr[idx] = alpha * (aptr[idx] + aptr[idx - 1] + aptr[idx + 1]
                                      + aptr[rowip1 + j] + aptr[rowim1 + j]);
            }
        }
        // 2nd sweep: B → A
#pragma omp for collapse(2) schedule(static)
        for (int i = start; i < last; ++i) {
            const int rowi = i * stride;
            const int rowim1 = (i - 1) * stride;
            const int rowip1 = (i + 1) * stride;
            for (int j = start; j < last; ++j) {
                const int idx = rowi + j;
                aptr[idx] = alpha * (bptr[idx] + bptr[idx - 1] + bptr[idx + 1]
                                      + bptr[rowip1 + j] + bptr[rowim1 + j]);
            }
        }
    }
}
