#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
		std::vector<std::vector<double>>& E,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& F,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D,
		std::vector<std::vector<double>>& G)
{
    // Helper to fetch contiguous row pointer
    auto row = [](std::vector<std::vector<double>>& M, int i) -> double* {
        return &M[i][0];
    };

    /* 1) E = A * B   (ni x nk) * (nk x nj) -> (ni x nj) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* eRow = row(E, i);
        const double* aRow = row(A, i);
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* bCol = &B[0][j];
            for (int k = 0; k < nk; ++k) {
                sum += aRow[k] * bCol[k * nj];   // B[k][j]
            }
            eRow[j] = sum;
        }
    }

    /* 2) F = C * D   (nj x nm) * (nm x nl) -> (nj x nl) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double* fRow = row(F, i);
        const double* cRow = row(C, i);
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* dCol = &D[0][j];
            for (int k = 0; k < nm; ++k) {
                sum += cRow[k] * dCol[k * nl];   // D[k][j]
            }
            fRow[j] = sum;
        }
    }

    /* 3) G = E * F   (ni x nj) * (nj x nl) -> (ni x nl) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* gRow = row(G, i);
        const double* eRow = row(E, i);
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* fCol = &F[0][j];
            for (int k = 0; k < nj; ++k) {
                sum += eRow[k] * fCol[k * nl];   // F[k][j]
            }
            gRow[j] = sum;
        }
    }
}
