    // each i works on a distinct row and only reads
    // previous rows which are never written after their
    // respective i iterations.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        auto &rowi = A[i];
        // First part: compute L[i][j] (j < i)
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            // Row i: use already computed values in rowi[0..j-1]
            // Row k: read from previous rows
            for (int k = 0; k < j; ++k) {
                sum += rowi[k] * A[k][j];
            }
            rowi[j] -= sum;
            rowi[j] /= A[j][j];
        }

        // Second part: compute U[i][j] (j >= i)
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += rowi[k] * A[k][j];
            }
            rowi[j] -= sum;
        }
    }
}
