/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    /* Ensure matrix dimensions are correct */
    if ((int)A.size() != m || (int)Q.size() != m ||
        (int)R.size() != n || (int)R[0].size() < n)
        return;   // or throw an exception in a real setting

    for (int k = 0; k < n; ++k)
    {
        /* Step 1: compute ||q_k|| = sqrt(sum_i A[i][k]^2) */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm)
        for (int i = 0; i < m; ++i)
            nrm += A[i][k] * A[i][k];
        R[k][k] = std::sqrt(nrm);
        /* Avoid division by zero – the original algorithm assumes all columns are linearly independent. */
        double invR = 1.0 / R[k][k];

        /* Step 2: normalize column k into Q */
#pragma omp parallel for
        for (int i = 0; i < m; ++i)
            Q[i][k] = A[i][k] * invR;

        /* Step 3: orthogonalize remaining columns */
#pragma omp parallel for schedule(static)
        for (int j = k + 1; j < n; ++j)
        {
            /* Compute R[k][j] = Q_k · A_j */
            double dot = 0.0;
            for (int i = 0; i < m; ++i)
                dot += Q[i][k] * A[i][j];
            R[k][j] = dot;

            /* Subtract projection from A_j */
            for (int i = 0; i < m; ++i)
                A[i][j] -= Q[i][k] * dot;
        }
    }
}
