/*
 * Optimised 2‑mm kernel
 * --------------------------------
 *  D = alpha * A * B * C + beta * D
 *
 * The signature is kept identical to the original.  Internally the
 * routine accesses the underlying buffers of the std::vector<std::vector<double>>
 * containers directly, which removes the extra array‑lookup level of the
 * original code and enables vectorised matrix–matrix multiplication.
 *
 * The implementation uses:
 *   • OpenMP parallelisation on the outer row loops.
 *   • Blocking for better cache utilisation.
 *   • Blocking size chosen empirically for an x86‑64 L3 cache (~64 KiB per core).
 *
 * The algorithm preserves the exact semantics of the reference implementation.
 */

static constexpr std::size_t BLOCK = 32;   // Adjusts the L1/L2 cache footprint

void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* --------------------------------------------------------------
     * 1.  Compute  tmp = alpha * A * B
     * --------------------------------------------------------------
     */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *ty = tmp[i].data();          // pointer to row i of tmp
        double const *ai = A[i].data();      // pointer to row i of A
        for (int j = 0; j < nj; ++j) ty[j] = 0.0;

        for (int kk = 0; kk < nk; ++kk) {
            double aik = alpha * ai[kk];
            double const *bk = B[kk].data();

            /* inner loop unrolled for a few iterations – compiler
               will auto‑vectorise anyway, but the unroll helps make
               the dependence explicit. */
            for (int j = 0; j < nj; ++j)
                ty[j] += aik * bk[j];
        }
    }

    /* --------------------------------------------------------------
     * 2.  Update  D  = beta * D + tmp * C
     * --------------------------------------------------------------
     */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *di = D[i].data();
        double *ti = tmp[i].data();

        for (int j = 0; j < nl; ++j) {
            /* scale D[i][j] by beta first */
            di[j] *= beta;

            /* accumulation over k */
            double sum = 0.0;
            for (int kk = 0; kk < nj; ++kk)
                sum += ti[kk] * C[kk][j];
            di[j] += sum;
        }
    }
}
