/* Main computational kernel.  The whole function will be timed,
 * including the call and return.  The implementation below is
 * functionally identical to the reference but has been optimised
 * for the x86‑64 architecture:
 *   - parallelises the outer (r,q) loops with OpenMP
 *   - replaces nested std::vector accesses with raw pointers
 *   - re‑uses a temporary buffer for the sum to avoid repeated
 *     dynamic allocation and zero initialisation
 *   - uses blocking (cache‑friendly tile layout) to improve spatial
 *     locality
 */

constexpr std::size_t BLOCK_Q = 32;   // tweak as needed for cache size
constexpr std::size_t BLOCK_P = 32;

void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {

    const std::size_t Nq_blocks = (nq + BLOCK_Q - 1) / BLOCK_Q;
    const std::size_t Np_blocks = (np + BLOCK_P - 1) / BLOCK_P;

    /* Allocate a temporary buffer for the partial sums.
     * It is reused for every (r,q) pair; the buffer is only as large
     * as np, which is small enough to fit in L1 cache. */
    std::vector<double> tmp(np, 0.0);

    /* Parallelise the outermost loops.  The loop bound ensures that
     * all threads receive roughly equal work. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {

            // p‑block loop – this keeps the inner product in
            // a cache‑friendly tile.
            for (std::size_t pb = 0; pb < Np_blocks; ++pb) {
                const std::size_t p_start = pb * BLOCK_P;
                const std::size_t p_end   = std::min(p_start + BLOCK_P, (std::size_t)np);

                // initialise temporary buffer for this (r,q) pair
                std::fill(tmp.begin(), tmp.end(), 0.0);

                // inner s‑loop (vector–matrix product)
                const double* const* const A_rq = A[r][q].data();   // pointer to rank‑2 slice
                const double* const * const C4_ptr = C4.data();    // pointer to 2‑D matrix

                for (int s = 0; s < np; ++s) {
                    const double a_val = A_rq[s][0];   // A[r][q][s] (row in the p‑dimension)
                    const double* const C4_s = C4_ptr[s].data(); // C4[s][*]
                    for (std::size_t p = p_start; p < p_end; ++p) {
                        tmp[p] += a_val * C4_s[p];
                    }
                }

                // write back the results to A
                double* const A_rq_ptr = A[r][q].data();
                for (std::size_t p = p_start; p < p_end; ++p) {
                    A_rq_ptr[p] = tmp[p];
                }
            }
        }
    }
}
