/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
		    int n,
		    std::vector<std::vector<std::vector<double>>>& A,
		    std::vector<std::vector<std::vector<double>>>& B) {

    const double coeff = 0.125;
    const int last = n - 1;

    for (int t = 1; t <= tsteps; ++t) {

        /* Compute B from A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < last; ++i)
            for (int j = 1; j < last; ++j)
                for (int k = 1; k < last; ++k) {
                    double center = A[i][j][k];
                    double val = coeff * (A[i+1][j][k] - 2.0 * center + A[i-1][j][k])
                               + coeff * (A[i][j+1][k] - 2.0 * center + A[i][j-1][k])
                               + coeff * (A[i][j][k+1] - 2.0 * center + A[i][j][k-1])
                               + center;
                    B[i][j][k] = val;
                }

        /* Compute A from B (swap roles) */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < last; ++i)
            for (int j = 1; j < last; ++j)
                for (int k = 1; k < last; ++k) {
                    double center = B[i][j][k];
                    double val = coeff * (B[i+1][j][k] - 2.0 * center + B[i-1][j][k])
                               + coeff * (B[i][j+1][k] - 2.0 * center + B[i][j-1][k])
                               + coeff * (B[i][j][k+1] - 2.0 * center + B[i][j][k-1])
                               + center;
                    A[i][j][k] = val;
                }
    }
}
