/*
 * Optimised kernel_atax
 *
 * The code is split into three phases:
 *   1. Initialise y to zero (parallel).
 *   2. Compute the product A * x into a temporary vector tmp, in parallel over
 *      the rows of A.  While doing this we also accumulate the contribution
 *      to the final vector y into a thread‐local buffer.  This avoids atomic
 *      updates.
 *   3. Combine all thread‐local buffers into the final y vector.
 *
 * The code retains exact semantics of the reference implementation.
 */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* 1. Zero out y  */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        y[j] = 0.0;

    /* 2. Main work in parallel over the rows of A */
    #pragma omp parallel
    {
        /* Each thread keeps a private buffer for its part of y */
        std::vector<double> local_y(n, 0.0);

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double sum = 0.0;
            /* tmp[i] = A[i] * x */
            const auto& Ai = A[i];
            for (int j = 0; j < n; ++j)
                sum += Ai[j] * x[j];
            tmp[i] = sum;

            /* accumulate into local_y */
            for (int j = 0; j < n; ++j)
                local_y[j] += Ai[j] * tmp[i];
        }

        /* 3. Reduce local_y into the global y */
        #pragma omp critical
        {
            for (int j = 0; j < n; ++j)
                y[j] += local_y[j];
        }
    }
}
