/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {

    /* Pointers to the underlying flat data for faster access */
    double *ex_ptr   = ex[0].data();   /* nx * ny elements */
    double *ey_ptr   = ey[0].data();   /* nx * ny elements */
    double *hz_ptr   = hz[0].data();   /* nx * ny elements */
    const double *fict = _fict_.data();

    /* Helper to compute linear index */
    #define IDX(i, j) ((i) * ny + (j))

    /* The kernel is split into four stages. */
    for (int t = 0; t < tmax; ++t) {
        /* Stage 1: update ey[0][j] = fict[t] */
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny; ++j) {
            ey_ptr[IDX(0, j)] = fict[t];
        }

        /* Stage 2: update ey[i][j] = ey[i][j] - 0.5 * (hz[i][j] - hz[i-1][j]) */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < nx; ++i) {
            for (int j = 0; j < ny; ++j) {
                int idx = IDX(i, j);
                ey_ptr[idx] -= 0.5 * (hz_ptr[idx] - hz_ptr[IDX(i-1, j)]);
            }
        }

        /* Stage 3: update ex[i][j] = ex[i][j] - 0.5 * (hz[i][j] - hz[i][j-1]) */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx; ++i) {
            for (int j = 1; j < ny; ++j) {
                int idx = IDX(i, j);
                ex_ptr[idx] -= 0.5 * (hz_ptr[idx] - hz_ptr[IDX(i, j-1)]);
            }
        }

        /* Stage 4: update hz[i][j] = hz[i][j] - 0.7 *
           (ex[i][j+1] - ex[i][j] + ey[i+1][j] - ey[i][j]) */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx-1; ++i) {
            for (int j = 0; j < ny-1; ++j) {
                int idx = IDX(i, j);
                hz_ptr[idx] -= 0.7 * (ex_ptr[IDX(i, j+1)] - ex_ptr[idx]
                                      + ey_ptr[IDX(i+1, j)] - ey_ptr[idx]);
            }
        }
    }

    /* Clean up macro */
    #undef IDX
}
