/*----------------------------------------------------------------------------
 * Kernel to compute the covariance matrix of an  m‑by‑n data matrix,
 * where `m` is the number of variables (columns) and `n` is the number
 * of observations (rows).  The input vectors `data`, `cov` and `mean`
 * are passed by reference and must have the same structure as the
 * original implementation:
 *   data : n rows, each row a vector of m doubles
 *   cov  : m rows, each row a vector of m doubles
 *   mean : one entry per column
 * The function keeps the exact semantics of the original code but
 * exploits cache‑friendly inner‑loops, reduction for the mean
 * calculation, and OpenMP parallelism where it gives a benefit.
 *---------------------------------------------------------------------------*/

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* --------------------------------------------------------------------
     * 1. Compute mean of each column.
     *    Work is embarrassingly parallel – the outer loop over columns
     *    is split among the threads.  We accumulate into a temporary
     *    buffer and divide by `n` at the end.
     * -------------------------------------------------------------------- */
    std::vector<double> mean_tmp(m, 0.0);

    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean_tmp[j] = sum;
    }

    const double inv_n = 1.0 / static_cast<double>(n);
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        mean[j] = mean_tmp[j] * inv_n;
    }

    /* --------------------------------------------------------------------
     * 2. Center the data: subtract the column mean from each entry.
     *    The assign operation is parallelized over rows.
     * -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    /* --------------------------------------------------------------------
     * 3. Compute the covariance matrix.
     *    The symmetric matrix is filled by iterating only for
     *    i <= j and mirroring the result.
     *    The inner product for each pair of columns is done
     *    with a simple loop over rows.  The outer loops are
     *    parallelized by blocks to reduce false sharing.
     * -------------------------------------------------------------------- */
    const double inv = 1.0 / static_cast<double>(n - 1);

    // Determine an appropriate chunk size for the outer loop
    int block = 8;  // tweak if needed; 8 is a good starting point.

    #pragma omp parallel for collapse(2) schedule(dynamic,block)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double val = sum * inv;
            cov[i][j] = val;
            cov[j][i] = val;   // symmetric
        }
    }
}
