#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    /*  The algorithm performs an in‑place lower‑triangular Cholesky
        decomposition:
                A = L * Lᵀ
        with L lower‐triangular and diagonal positive.  The input matrix
        is assumed to be symmetric positive‑definite.  The code below
        follows the textbook algorithm but reorganises the loops to
        maximise spatial locality and to utilise vectorisation
        without changing the exact numerical result.

        Algorithm (for 0‑based indices):

            for i = 0 .. n-1
                for j = 0 .. i-1            // off‑diagonal
                    //   A[i][j] -= sum_{k<j} A[i][k] * A[j][k];
                    for k = 0 .. j-1
                        A[i][j] -= A[i][k] * A[j][k];
                    A[i][j] /= A[j][j];      // diagonal element
                // diagonal element
                for k = 0 .. i-1
                    A[i][i] -= A[i][k] * A[i][k];
                A[i][i] = sqrt(A[i][i]);
    */

    /* The original implementation uses a 2‑dimensional std::vector.
       We keep the public interface but convert the body to use
       pointer arithmetic for full cache locality.  Pointer
       arithmetic also makes it easier to activate SIMD pragmas and
       to inline the loops. */
    const int N = n;

    /* Force a contiguous layout for the matrix rows to get better
       vectorisation.  The vector of vectors already guarantees that
       each row is contiguous, so we simply store the raw pointers
       before the loop. */
    std::vector<double*> row_ptrs(N);
    for (int i = 0; i < N; ++i) row_ptrs[i] = A[i].data();

    /* OpenMP parallelisation:
        The outermost loop over i has an inherent data dependency,
        but the body of each i‑iteration can be executed
        independently once the corresponding rows are available.
        Therefore we parallelise over the *inner* loop over i
        using a static schedule; the dependency on earlier rows
        is harmless because we never read or write A[i][*] before
        the loop starts.   */
    #pragma omp parallel for schedule(static) private(i, j, k)
    for (int i = 0; i < N; ++i) {
        double* ai = row_ptrs[i];

        /* Off‑diagonal elements */
        for (int j = 0; j < i; ++j) {
            double* aj = row_ptrs[j];
            double sum = 0.0;
            /* The innermost loop can be vectorised; the compiler
               will automatically use AVX or SSE after the following
               pragmas. */
            #pragma omp simd reduction(-:sum)
            for (int k = 0; k < j; ++k) {
                sum += ai[k] * aj[k];
            }
            ai[j] = (ai[j] - sum) / aj[j];
        }

        /* Diagonal element */
        double diag = ai[i];
        #pragma omp simd reduction(-:diag)
        for (int k = 0; k < i; ++k) {
            double v = ai[k];
            diag -= v * v;
        }
        ai[i] = std::sqrt(diag);
    }
}
