/* Optimised version of the LU‑decomposition kernel.
   It keeps the external signature unchanged but replaces the
   double nested std::vector access with raw pointers and
   explicitly unrolled inner loops where possible.
   The code is also annotated with OpenMP pragmas for any
   trivially independent work.  */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    // Work with raw row pointers for better cache locality
    std::vector<double*> rowA(n);
    for (int i = 0; i < n; ++i)
        rowA[i] = A[i].data();

    /* === LU Decomposition (Doolittle) === */
    for (int i = 0; i < n; ++i) {
        double* Ai = rowA[i];
        double* Aii = Ai + i;                      // A[i][i]
        double Aii_val = *Aii;

        /* --- Lower part (L) --- */
#pragma omp simd
        for (int j = 0; j < i; ++j) {
            double w = Ai[j];
#pragma omp simd
            for (int k = 0; k < j; ++k)
                w -= Ai[k] * rowA[k][j];
            Ai[j] = w / rowA[j][j];               // divide by pivot
        }

        /* --- Upper part (U) --- */
#pragma omp simd
        for (int j = i; j < n; ++j) {
            double w = Ai[j];
#pragma omp simd
            for (int k = 0; k < i; ++k)
                w -= Ai[k] * rowA[k][j];
            Ai[j] = w;                             // keep as is
        }
    }

    /* === Forward substitution (Ly = b) === */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
#pragma omp simd
        for (int j = 0; j < i; ++j)
            w -= rowA[i][j] * y[j];
        y[i] = w;
    }

    /* === Backward substitution (Ux = y) === */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
#pragma omp simd
        for (int j = i + 1; j < n; ++j)
            w -= rowA[i][j] * x[j];
        x[i] = w / rowA[i][i];
    }
}

