void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {
    /* Size checks – guarantees the same behaviour as the original */
    check_size(A.size(),   static_cast<std::size_t>(n), "A rows");
    check_size(u1.size(),  static_cast<std::size_t>(n), "u1");
    check_size(v1.size(),  static_cast<std::size_t>(n), "v1");
    check_size(u2.size(),  static_cast<std::size_t>(n), "u2");
    check_size(v2.size(),  static_cast<std::size_t>(n), "v2");
    check_size(w.size(),   static_cast<std::size_t>(n), "w");
    check_size(x.size(),   static_cast<std::size_t>(n), "x");
    check_size(y.size(),   static_cast<std::size_t>(n), "y");
    check_size(z.size(),   static_cast<std::size_t>(n), "z");

    for (auto &row : A)
        check_size(row.size(), static_cast<std::size_t>(n), "A cols");

    /* --------------------------------------------------------------------
       1. First double loop: update A
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        auto &Ai = A[i];
        for (int j = 0; j < n; ++j)
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
    }

    /* --------------------------------------------------------------------
       2. Second double loop: update x
       ------------------------------------------------------------------ */
    /* We compute in parallel over i and accumulate in a private buffer for x to avoid
       false sharing.  Since x is overwritten in the next stage this is safe. */
    std::vector<double> x_tmp(n, 0.0);

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        for (int j = 0; j < n; ++j) {
            xi += beta * A[j][i] * y[j];
        }
        x_tmp[i] = xi;
    }

    /* now copy back to x */
    std::copy(x_tmp.begin(), x_tmp.end(), x.begin());

    /* --------------------------------------------------------------------
       3. Add z to x
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* --------------------------------------------------------------------
       4. Fourth double loop: update w
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];
        const auto &Ai = A[i];
        for (int j = 0; j < n; ++j)
            wi += alpha * Ai[j] * x[j];
        w[i] = wi;
    }
}
