#include <vector>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r)
{
    /* Zero out s – this is independent of the remaining computation,
       hence it can be done with a simple std::fill. */
    std::fill(s.begin(), s.end(), 0.0);

    /* Zero out q – also independent of the remaining computation. */
    std::fill(q.begin(), q.end(), 0.0);

    /* Parallelize the computation over the rows of A (index i). */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ri = r[i];
        double qi = 0.0;
        double* aRow = A[i].data();           // pointer to the i‑th row
        double* pRow = p.data();              // pointer to p
        /* Each thread updates q[i] completely (private `qi`),
           and accumulates contributions to s[j] for all j. */
        for (int j = 0; j < m; ++j) {
            double a = aRow[j];
            /* We cannot use a reduction on the vector s directly,
               so we perform the accumulation in a critical section
               that only protects the write to s[j].   */
            #pragma omp atomic
            s[j] += ri * a;
            qi += a + pRow[j];
        }
        q[i] = qi;
    }
}
