#include <vector>
#include <omp.h>

/* Optimised kernel for speed – no functional changes */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {

    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    /* Local 2‑D arrays stored in a single vector for cache friendliness */
    std::vector<double> ptmp(n * n, 0.0);
    std::vector<double> qtmp(n * n, 0.0);
    auto idx = [n](int i, int j) -> size_t { return i * n + j; };

    for (int t = 0; t < tsteps; ++t) {

        /* First sweep – operate on v */
        #pragma omp parallel for schedule(static) collapse(1)
        for (int i = 1; i < n - 1; ++i) {
            /* initialise edge rows */
            v[0][i] = 1.0;
            ptmp[idx(i, 0)] = 0.0;
            qtmp[idx(i, 0)] = v[0][i];

            /* forward sweep: compute p and q for this column */
            for (int j = 1; j < n - 1; ++j) {
                double denom = a * ptmp[idx(i, j - 1)] + b;
                ptmp[idx(i, j)] = -c / denom;
                double num = (-d * u[j][i - 1]
                              + (1.0 + 2.0 * d) * u[j][i]
                              - f * u[j][i + 1]
                              - a * qtmp[idx(i, j - 1)]);
                qtmp[idx(i, j)] = num / denom;
            }

            v[n - 1][i] = 1.0;

            /* backward sweep: compute v */
            for (int j = n - 2; j >= 1; --j) {
                v[j][i] = ptmp[idx(i, j)] * v[j + 1][i] + qtmp[idx(i, j)];
            }
        }

        /* Second sweep – operate on u */
        #pragma omp parallel for schedule(static) collapse(1)
        for (int i = 1; i < n - 1; ++i) {
            u[i][0] = 1.0;
            ptmp[idx(i, 0)] = 0.0;
            qtmp[idx(i, 0)] = u[i][0];

            for (int j = 1; j < n - 1; ++j) {
                double denom = d * ptmp[idx(i, j - 1)] + e;
                ptmp[idx(i, j)] = -f / denom;
                double num = (-a * v[i - 1][j]
                              + (1.0 + 2.0 * a) * v[i][j]
                              - c * v[i + 1][j]
                              - d * qtmp[idx(i, j - 1)]);
                qtmp[idx(i, j)] = num / denom;
            }

            u[i][n - 1] = 1.0;
            for (int j = n - 2; j >= 1; --j) {
                u[i][j] = ptmp[idx(i, j)] * u[i][j + 1] + qtmp[idx(i, j)];
            }
        }
    }
}
