#include <omp.h>

/* Optimised kernel_deriche – preserves exact semantics of the reference implementation.
   The function signature is unchanged to satisfy the harness. */
void kernel_deriche(int w, int h, double alpha,
		    std::vector<std::vector<float>>& imgIn,
		    std::vector<std::vector<float>>& imgOut,
		    std::vector<std::vector<float>>& y1,
		    std::vector<std::vector<float>>& y2)
{
    /* ---------- Pre‑compute constants -------------------------------------------------- */
    const float expA  = std::exp(-alpha);
    const float exp2A = expA*expA;
    const float k = 1.0f - expA*(1.0f - expA)
                    / (1.0f + 2.0f*alpha*expA - exp2A);

    const float a1 =  k;
    const float a2 =  k*expA * (float)(alpha - 1.0);
    const float a3 =  k*expA * (float)(alpha + 1.0);
    const float a4 = -k*exp2A;
    const float a5 =  k;
    const float a6 =  k*expA * (float)(alpha - 1.0);
    const float a7 =  k*expA * (float)(alpha + 1.0);
    const float a8 = -k*exp2A;

    const float b1 = std::pow(2.0f, -alpha);
    const float b2 = -exp2A;
    const float c1 = 1.0f;   /* c1 and c2 are identical in the original code */
    const float c2 = 1.0f;

    /* ---------- Helper to obtain pointer to a row ------------------------------- */
    auto row = [](std::vector<std::vector<float>>& mat, int i) -> float* {
        return const_cast<float*>(mat[i].data());
    };

    /* ---------- 1. Forward 1-D filtering ------------------------------------- */
#pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float* in  = row(imgIn, i);
        float* out = row(y1, i);

        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            float val = a1*in[j] + a2*xm1 + b1*ym1 + b2*ym2;
            out[j] = val;
            xm1 = in[j];
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* ---------- 2. Reverse 1-D filtering ------------------------------------ */
#pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        const float* in = row(imgIn, i);
        float* out = row(y2, i);

        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h-1; j >= 0; --j) {
            float val = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            out[j] = val;
            xp2 = xp1;
            xp1 = in[j];
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* ---------- 3. Sum along the first dimension ----------------------------- */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    /* ---------- 4. Forward 1-D filtering along the second dimension ----------- */
#pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float* in = row(imgOut, i);
            float* out = row(y1, i);
            float val = a5*in[j] + a6*tm1 + b1*ym1 + b2*ym2;
            out[j] = val;
            tm1 = in[j];
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* ---------- 5. Reverse 1-D filtering along the second dimension ---------- */
#pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const float* in = row(imgOut, i);
            float* out = row(y2, i);
            float val = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            out[j] = val;
            tp2 = tp1;
            tp1 = in[j];
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* ---------- 6. Final sum along the second dimension ----------------------- */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
